#include <stddef.h>
typedef long ssize_t;
#define RK_MAX 6
int  rk_idx;
int  rk_ret[RK_MAX];
char rk_byte[RK_MAX];
/* FUNCTION: read */
ssize_t read(int fd, void *buf, size_t count) {
    (void)fd; (void)count;
    int i = rk_idx;
    rk_idx = i + 1;
    if (i >= RK_MAX) return 0;
    if (rk_ret[i] > 0) ((char *)buf)[0] = rk_byte[i];
    return (ssize_t)rk_ret[i];
}
